sql:
SELECT date, COUNT(*) AS record_count
FROM stock_prices
GROUP BY date;

SELECT exchange_name
FROM stock_exchanges
WHERE location = 'United States';

SELECT COUNT(*) AS total_exchanges, location
FROM stock_exchanges
GROUP BY location;

SELECT market_id, COUNT(dataset_id) AS number_of_datasets
FROM datasets
GROUP BY market_id;

SELECT COUNT(*) AS number_of_us_exchanges
FROM stock_exchanges
WHERE location = 'United States';

SELECT dataset_name, start_date
FROM datasets
ORDER BY start_date DESC;

external_knowledge:
- 'most popular datasets' refers to datasets with the highest total access counts during a specified period;
- 'detailed information' includes the dataset's market and exchange IDs, along with unique user count and total access count;
- 'past year' in the context of this question refers to the year 2023.
